/* Ethernet MAC/PHY link status and configuration */
#ifndef ETH_DRV_H
#define ETH_DRV_H

#include <stdint.h>

#define ETH_SPEED_10M   0
#define ETH_SPEED_100M  1
#define ETH_SPEED_1000M 2

#define ETH_DUPLEX_HALF 0
#define ETH_DUPLEX_FULL 1

typedef struct {
    uint8_t  mac_addr[6];
    uint8_t  speed;      /* ETH_SPEED_* */
    uint8_t  duplex;     /* ETH_DUPLEX_* */
    uint8_t  autoneg;    /* 1 = enable autonegotiation */
} eth_config_t;

int  eth_init(const eth_config_t *cfg);
int  eth_send(const uint8_t *frame, uint16_t len);
int  eth_recv(uint8_t *buf, uint16_t buf_len);
void eth_deinit(void);

#endif

