#define ETH_DRV_H

#include <stdint.h>

/* Speed macros CHANGED to bitmask flags — breaks equality comparisons */
#define ETH_SPEED_10M   (1U << 0)   /* was 0 */
#define ETH_SPEED_100M  (1U << 1)   /* was 1 */
#define ETH_SPEED_1000M (1U << 2)   /* was 2 */

#define ETH_DUPLEX_HALF (1U << 0)   /* was 0 */
#define ETH_DUPLEX_FULL (1U << 1)   /* was 1 */

typedef struct {
    uint8_t  mac_addr[6];
    uint8_t  speed;      /* ETH_SPEED_* bitmask */
    uint8_t  duplex;     /* ETH_DUPLEX_* bitmask */
    uint8_t  autoneg;    /* 1 = enable autonegotiation */
} eth_config_t;

int  eth_init(const eth_config_t *cfg);
/* eth_send signature changed: added flags parameter */
int  eth_send(const uint8_t *frame, uint16_t len, uint32_t flags);
int  eth_recv(uint8_t *buf, uint16_t buf_len);
void eth_deinit(void);

#endif

